mapper.select:
select 
from exam_record er
left join exam e on er.exam_id = e.id
left join paper p on er.paper_id = p.id
left join student s on er.student_id = s.id


        and er.exam_id = #{examId}


        and er.student_id = #{studentId}


        and er.status = #{status}


        and e.teacher_id = #{teacherId}


order by er.create_time desc

mapper.update:
update exam_record
submit_time = #{submitTime}, total_score = #{totalScore}, objective_score = #{objectiveScore}, subjective_score = #{subjectiveScore}, status = #{status},
where id = #{id}
